  auto obj = HyperLogLog<std::string>(static_cast<int16_t>(14));

  std::vector<std::thread> threads1;
  for (uint16_t i = 0; i < 10; i++) {
    threads1.emplace_back(std::thread([&]() { obj.AddElem("Welcome to CMU DB (15-445/645)"); }));
