template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find position of leftmost (most significant) 1 bit
  // This is essentially BITSET_CAPACITY - number of leading zeros
  // If no bit is set, return BITSET_CAPACITY + 1
  for (int i = BITSET_CAPACITY - 1; i >= 0; i--) {
    if (bset[i]) {
      return BITSET_CAPACITY - i;  // Position from the right, starting at 1
    }
  }
  return BITSET_CAPACITY + 1;  // No bit set
}

