  // Calculate hash
  hash_t hash = CalculateHash(val);

  // Extract bucket index from first n_bits
  uint32_t num_buckets = dense_bucket_.size();
  uint32_t n_bits = 0;
  uint32_t temp = num_buckets;
  while (temp > 1) {
    n_bits++;
    temp >>= 1;
  }

  uint32_t bucket_idx = hash & ((1u << n_bits) - 1);

  // Calculate position of leftmost one bit in the hash
  // Position is 0-indexed from the right
  uint64_t position;
  if (hash == 0) {
    position = 64;
  } else {
    position = 63 - __builtin_clzll(hash);
  }

  // Split position into dense (lower 4 bits) and overflow (upper bits)
  uint8_t dense_value = position & 0xF;
  uint8_t overflow_value = position >> 4;

  // Update dense bucket with maximum value
  std::bitset<DENSE_BUCKET_SIZE> new_dense(dense_value);
  if (new_dense.to_ullong() > dense_bucket_[bucket_idx].to_ullong()) {
    dense_bucket_[bucket_idx] = new_dense;
  }

  // Update overflow bucket if needed
  if (overflow_value > 0) {
    auto it = overflow_bucket_.find(bucket_idx);
    uint8_t current_overflow = 0;
    if (it != overflow_bucket_.end()) {
      current_overflow = it->second.to_ullong();
    }
    if (overflow_value > current_overflow) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
    }
  }
}

