#include "primer/hyperloglog_presto.h"
#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : cardinality_(0) {
  // Initialize dense buckets based on n_leading_bits
  if (n_leading_bits > 0) {
    dense_bucket_.resize(1 << n_leading_bits, std::bitset<DENSE_BUCKET_SIZE>(0));
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  // Handle invalid n_leading_bits
  if (dense_bucket_.empty()) {
    return;
  }

  // Calculate hash
  hash_t hash = CalculateHash(val);

  // Extract bucket index from first n_bits
  uint32_t num_buckets = dense_bucket_.size();
  uint32_t n_bits = 0;
  uint32_t temp = num_buckets;
  while (temp > 1) {
    n_bits++;
    temp >>= 1;
  }

  uint32_t bucket_idx = hash & ((1u << n_bits) - 1);

  // Calculate position of leftmost one bit in the hash
  // Position is 0-indexed from the right
  uint64_t position;
  if (hash == 0) {
    position = 64;
  } else {
    position = 63 - __builtin_clzll(hash);
  }

  // Split position into dense (lower 4 bits) and overflow (upper bits)
  uint8_t dense_value = position & 0xF;
  uint8_t overflow_value = position >> 4;

  // Update dense bucket with maximum value
  std::bitset<DENSE_BUCKET_SIZE> new_dense(dense_value);
  if (new_dense.to_ullong() > dense_bucket_[bucket_idx].to_ullong()) {
    dense_bucket_[bucket_idx] = new_dense;
  }

  // Update overflow bucket if needed
  if (overflow_value > 0) {
    auto it = overflow_bucket_.find(bucket_idx);
    uint8_t current_overflow = 0;
    if (it != overflow_bucket_.end()) {
      current_overflow = it->second.to_ullong();
    }
    if (overflow_value > current_overflow) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
    }
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  // Handle empty dense bucket
  if (dense_bucket_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Calculate harmonic mean of 2^(-register values)
  double harmonic_mean = 0.0;
  for (size_t i = 0; i < dense_bucket_.size(); i++) {
    uint8_t dense_val = dense_bucket_[i].to_ullong();
    uint8_t overflow_val = 0;
    auto it = overflow_bucket_.find(i);
    if (it != overflow_bucket_.end()) {
      overflow_val = it->second.to_ullong();
    }

    // Combine dense and overflow values
    // full_value = (overflow << 4) | dense
    uint64_t full_value = (static_cast<uint64_t>(overflow_val) << 4) | dense_val;
    harmonic_mean += std::pow(2.0, -static_cast<double>(full_value));
  }

  // Apply HyperLogLog formula
  double m = dense_bucket_.size();
  double result = CONSTANT * m * m / harmonic_mean;

  // Round to nearest integer
  cardinality_ = static_cast<uint64_t>(result + 0.5);
}

