namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  // Initialize registers based on n_bits
  if (n_bits_ >= 0) {
    registers_.resize(1 << n_bits_, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  // Convert hash to bitset
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find position of leftmost (most significant) 1 bit
  // This is essentially BITSET_CAPACITY - number of leading zeros
  // If no bit is set, return BITSET_CAPACITY + 1
  for (int i = BITSET_CAPACITY - 1; i >= 0; i--) {
    if (bset[i]) {
      return BITSET_CAPACITY - i;  // Position from the right, starting at 1
    }
  }
  return BITSET_CAPACITY + 1;  // No bit set
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  // Handle invalid n_bits
  if (n_bits_ <= 0) {
    return;
  }

  // Calculate hash
  hash_t hash = CalculateHash(val);

  // Extract bucket index from first n_bits
  uint32_t bucket_idx = hash & ((1u << n_bits_) - 1);

  // Get remaining bits and find position of leftmost one
  hash_t remaining = hash >> n_bits_;
  std::bitset<BITSET_CAPACITY> bset = ComputeBinary(remaining);
  uint64_t position = PositionOfLeftmostOne(bset);

  // Update register with maximum value (thread-safe)
  {
    std::lock_guard<std::mutex> lock(mutex_);
    registers_[bucket_idx] = std::max(registers_[bucket_idx], static_cast<uint8_t>(position));
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  // Handle invalid n_bits
  if (n_bits_ < 0 || registers_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Calculate harmonic mean of 2^(-register values)
  double harmonic_mean = 0.0;
  for (uint8_t reg_value : registers_) {
    harmonic_mean += std::pow(2.0, -static_cast<double>(reg_value));
  }

  // Apply HyperLogLog formula
  double m = 1.0 * (1 << n_bits_);  // Number of registers
  double result = CONSTANT * m * m / harmonic_mean;

  // Round to nearest integer
  cardinality_ = static_cast<size_t>(result + 0.5);
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub
