  double harmonic_mean = 0.0;
  for (uint8_t reg_value : registers_) {
    harmonic_mean += std::pow(2.0, -static_cast<double>(reg_value));
  }

  // Apply HyperLogLog formula
  double m = 1.0 * (1 << n_bits_);  // Number of registers
  double result = CONSTANT * m * m / harmonic_mean;

  // Round to nearest integer
  cardinality_ = static_cast<size_t>(result + 0.5);
}

